    10→
    11→const PAGE_SIZE = siteConfig.pagination.posts;
    12→
    13→export function generateStaticParams() {
    14→  if (getPostsBasePath() !== 'posts') return [{ page: '_' }]; // Route disabled; custom path handles this
    15→  const allPosts = getListingPosts();
    16→  const totalPages = Math.ceil(allPosts.length / PAGE_SIZE);
    17→
    18→  // Generate params for page 2 to totalPages (page 1 is handled by /posts/page.tsx)
    19→  if (totalPages <= 1) return [{ page: '2' }];
    20→
    21→  return Array.from({ length: totalPages - 1 }, (_, i) => ({
    22→    page: (i + 2).toString(),
    23→  }));
    24→}
    25→
    26→export const dynamicParams = false;
    27→
    28→export async function generateMetadata({ params }: { params: Promise<{ page: string }> }): Promise<Metadata> {
    29→  const { page } = await params;
    30→  return {
    31→    title: `${t('posts')} - ${page} | ${resolveLocale(siteConfig.title)}`,
    32→  };
    33→}
    34→
    35→export default async function PostsPage({ params }: { params: Promise<{ page: string }> }) {
    36→  const { page: pageStr } = await params;
    37→  const page = parseInt(pageStr);
    38→  const allPosts = getListingPosts();
    39→  const totalPages = Math.ceil(allPosts.length / PAGE_SIZE);
    40→
    41→  if (isNaN(page) || page < 2 || page > totalPages) notFound();
    42→
    43→  const start = (page - 1) * PAGE_SIZE;
    44→  const end = start + PAGE_SIZE;
    45→  const posts = allPosts.slice(start, end);
    46→
    47→  return (
    48→    <div className="layout-main">
    49→      <PageHeader
    50→        titleKey="posts"
    51→        subtitleKey="page_of_total"
    52→        subtitleParams={{ page, total: totalPages }}
    53→        className="mb-12"
    54→      />
    55→
    56→      <PostList posts={posts} />
    57→
    58→      <div className="mt-12">
    59→        <Pagination currentPage={page} totalPages={totalPages} basePath="/posts" />
    60→      </div>
    61→    </div>
    62→  );
    63→}
