     1→import { getPostBySlug, getAllPosts, getRelatedPosts, getSeriesPosts, getSeriesData, getAdjacentPosts, buildSlugRegistry, getBacklinks, PostData } from '@/lib/markdown';
     2→import { notFound } from 'next/navigation';
     3→import PostLayout from '@/layouts/PostLayout';
     4→import SimpleLayout from '@/layouts/SimpleLayout';
     5→import { Metadata } from 'next';
     6→import { siteConfig } from '../../../../site.config';
     7→import { resolveLocale } from '@/lib/i18n';
     8→import { getPostsBasePath, getPostUrl } from '@/lib/urls';
     9→import { buildPostJsonLd, serializeJsonLd } from '@/lib/json-ld';
    10→
    11→function safeDecodeParam(param: string): string {
    12→  try {
    13→    return decodeURIComponent(param);
    14→  } catch {
    15→    return param;
    16→  }
    17→}
    18→
    19→function resolvePostFromParam(rawSlug: string) {
    20→  const decoded = safeDecodeParam(rawSlug);
    21→  return (
    22→    getPostBySlug(decoded) ||
    23→    getPostBySlug(rawSlug) ||
    24→    getPostBySlug(decoded.normalize('NFC')) ||
    25→    getPostBySlug(decoded.normalize('NFD'))
    26→  );
    27→}
    28→
    29→/**
    30→ * Generates the static paths for all blog posts at build time.
    31→ * This ensures fast page loads and SEO optimization.
    32→ */
    33→export async function generateStaticParams() {
    34→  if (getPostsBasePath() !== 'posts') return [{ slug: '_' }]; // Route disabled; custom path handles this
    35→  const posts = getAllPosts();
    36→  if (posts.length === 0) return [{ slug: '_' }];
    37→  // Work around Next dev static-param checks for percent-encoded Unicode paths
    38→  // under `output: "export"` by including encoded variants only in development.
    39→  // Production export keeps raw segment values.
    40→  const slugs = new Set<string>();
    41→  for (const post of posts) {
    42→    slugs.add(post.slug);
    43→    if (process.env.NODE_ENV !== 'production') {
    44→      slugs.add(encodeURIComponent(post.slug));
    45→    }
    46→  }
    47→  return Array.from(slugs).map((slug) => ({ slug }));
    48→}
    49→
    50→export const dynamicParams = false;
    51→
    52→export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }): Promise<Metadata> {
    53→  const { slug: rawSlug } = await params;
    54→  const post = resolvePostFromParam(rawSlug);
    55→
    56→  if (!post) {
    57→    return {
    58→      title: 'Post Not Found',
    59→    };
    60→  }
    61→
    62→  const ogImage = post.coverImage && !post.coverImage.startsWith('text:') && !post.coverImage.startsWith('./')
    63→    ? post.coverImage
    64→    : siteConfig.ogImage;
    65→
    66→  return {
    67→    title: `${post.title} | ${resolveLocale(siteConfig.title)}`,
    68→    description: post.excerpt,
    69→    openGraph: {
    70→      title: post.title,
    71→      description: post.excerpt,
    72→      type: 'article',
    73→      publishedTime: post.date,
    74→      authors: post.authors,
    75→      images: [
    76→        {
    77→          url: ogImage,
    78→          width: 1200,
    79→          height: 630,
    80→          alt: post.title,
    81→        },
    82→      ],
    83→      siteName: resolveLocale(siteConfig.title),
    84→    },
    85→    twitter: {
    86→      card: 'summary_large_image',
    87→      title: post.title,
    88→      description: post.excerpt,
    89→      images: [ogImage],
    90→    },
    91→  };
    92→}
    93→
    94→export default async function PostPage({
    95→  params,
    96→}: {
    97→  params: Promise<{ slug: string }>;
    98→}) {
    99→  const { slug: rawSlug } = await params;
   100→  const slug = safeDecodeParam(rawSlug);
   101→  const post = resolvePostFromParam(rawSlug);
   102→
   103→  if (!post) {
   104→    notFound();
   105→  }
   106→
   107→  // Determine layout based on frontmatter
   108→  const layout = post.layout || 'post';
   109→
   110→  const siteUrl = siteConfig.baseUrl.replace(/\/+$/, '');
   111→  const jsonLd = buildPostJsonLd({
   112→    post,
   113→    postUrl: `${siteUrl}${getPostUrl(post)}`,
   114→    siteTitle: resolveLocale(siteConfig.title),
   115→    siteUrl,
   116→    defaultOgImage: siteConfig.ogImage,
   117→  });
   118→  const jsonLdScript = <script type="application/ld+json" dangerouslySetInnerHTML={{ __html: serializeJsonLd(jsonLd) }} />;
   119→
   120→  if (layout === 'simple') {
   121→    return <>{jsonLdScript}<SimpleLayout post={post} /></>;
   122→  }
   123→
   124→  const relatedPosts = getRelatedPosts(slug);
   125→  const { prev, next } = getAdjacentPosts(slug);
   126→  const slugRegistry = buildSlugRegistry();
   127→  const backlinks = getBacklinks(slug);
   128→  let seriesPosts: PostData[] = [];
   129→  let seriesTitle: string | undefined;
   130→
   131→  if (post.series) {
   132→    seriesPosts = getSeriesPosts(post.series);
   133→    const seriesData = getSeriesData(post.series);
   134→    seriesTitle = seriesData?.title;
   135→  }
   136→
   137→  return (
   138→    <>
   139→      {jsonLdScript}
   140→      <PostLayout post={post} relatedPosts={relatedPosts} seriesPosts={seriesPosts} seriesTitle={seriesTitle} prevPost={prev} nextPost={next} backlinks={backlinks} slugRegistry={slugRegistry} />
   141→    </>
   142→  );
   143→}
