     1→import fs from 'fs';
     2→import path from 'path';
     3→import matter from 'gray-matter';
     4→import { siteConfig } from '../../site.config';
     5→import GithubSlugger from 'github-slugger';
     6→import { z } from 'zod';
     7→import { getPostUrl } from './urls';
     8→
     9→const contentDirectory = path.join(process.cwd(), 'content', 'posts');
    10→const pagesDirectory = path.join(process.cwd(), 'content');
    11→const seriesDirectory = path.join(process.cwd(), 'content', 'series');
    12→const booksDirectory = path.join(process.cwd(), 'content', 'books');
    13→const flowsDirectory = path.join(process.cwd(), 'content', 'flows');
    14→const notesDirectory = path.join(process.cwd(), 'content', 'notes');
    15→
    16→const ExternalLinkSchema = z.object({
    17→  name: z.string(),
    18→  url: z.string().url(),
    19→});
    20→
    21→const PostSchema = z.object({
    22→  title: z.string(),
    23→  date: z.union([z.string(), z.date()]).transform(val => new Date(val).toISOString().split('T')[0]).optional(),
    24→  subtitle: z.string().optional(),
    25→  excerpt: z.string().optional(),
    26→  category: z.string().optional().default('Uncategorized'),
    27→  tags: z.array(z.string()).optional().default([]),
    28→  authors: z.array(z.string()).optional(),
    29→  author: z.string().optional(),
    30→  layout: z.string().optional().default('post'),
    31→  series: z.string().optional(),
    32→  coverImage: z.string().optional(),
    33→  sort: z.enum(['date-desc', 'date-asc', 'manual']).optional().default('date-desc'),
    34→  posts: z.array(z.string()).optional(),
    35→  featured: z.boolean().optional().default(false),
    36→  pinned: z.boolean().optional().default(false),
    37→  draft: z.boolean().optional().default(false),
    38→  latex: z.boolean().optional().default(false),
    39→  toc: z.boolean().optional().default(true),
    40→  externalLinks: z.array(ExternalLinkSchema).optional().default([]),
    41→});
    42→
    43→export interface Heading {
    44→  id: string;
    45→  text: string;
    46→  level: number;
    47→}
    48→
    49→export interface ExternalLink {
    50→  name: string;
    51→  url: string;
    52→}
    53→
    54→export interface PostData {
    55→  slug: string;
    56→  title: string;
    57→  subtitle?: string;
    58→  date: string;
    59→  excerpt: string;
    60→  category: string;
    61→  tags: string[];
    62→  authors: string[];
    63→  layout?: string;
    64→  series?: string;
    65→  coverImage?: string;
    66→  sort?: 'date-desc' | 'date-asc' | 'manual';
    67→  posts?: string[];
    68→  featured?: boolean;
    69→  pinned?: boolean;
    70→  draft?: boolean;
    71→  latex?: boolean;
    72→  toc?: boolean;
    73→  externalLinks?: ExternalLink[];
    74→  readingTime: string;
    75→  content: string;
    76→  headings: Heading[];
    77→  contentLocales?: Record<string, { content: string; title?: string; excerpt?: string; headings?: Heading[] }>;
    78→}
    79→
    80→export function calculateReadingTime(content: string): string {
    81→  const wordsPerMinute = 200;
    82→  const hanCharsPerMinute = 300;
    83→
    84→  // Strip tags and common markdown syntax before counting.
    85→  const text = content
    86→    .replace(/<\/?[^>]+(>|$)/g, "")
    87→    .replace(/```[\s\S]*?```/g, "")
    88→    .replace(/`[^`]*`/g, "")
    89→    .replace(/!\[[^\]]*\]\([^)]+\)/g, "")
    90→    .replace(/\[([^\]]+)\]\([^)]+\)/g, "$1")
    91→    .replace(/[#*_~>\-[\]()]/g, " ");
    92→
    93→  const hanCharCount = (text.match(/[\u3400-\u4DBF\u4E00-\u9FFF\uF900-\uFAFF]/g) || []).length;
    94→  const latinWordCount = (text.match(/[A-Za-z0-9]+(?:['’-][A-Za-z0-9]+)*/g) || []).length;
    95→
    96→  const estimatedMinutes = (latinWordCount / wordsPerMinute) + (hanCharCount / hanCharsPerMinute);
    97→  const minutes = Math.max(1, Math.ceil(estimatedMinutes));
    98→  return `${minutes} min read`;
    99→}
   100→
   101→export function generateExcerpt(content: string): string {
   102→  let plain = content.replace(/^#+\s+/gm, '');
   103→  plain = plain.replace(/```[\s\S]*?```/g, '');
   104→  plain = plain.replace(/!\[[^\]]*\]\([^)]+\)/g, '');
   105→  plain = plain.replace(/\*\[([^\]]+)\*\]\([^)]+\)/g, '$1');
   106→  plain = plain.replace(/(\$\*\*|__|\*|_)/g, '');
   107→  plain = plain.replace(/`([^`]+)`/g, '$1');
   108→  plain = plain.replace(/^>\s+/gm, '');
   109→  plain = plain.replace(/\s+/g, ' ').trim();
   110→  
   111→  if (plain.length <= 160) {
   112→    return plain;
   113→  }
   114→  return plain.slice(0, 160).trim() + '...';
   115→}
   116→
   117→export function getHeadings(content: string): Heading[] {
   118→  const regex = /^(#{2,3})\s+(.*)$/gm;
   119→  const headings: Heading[] = [];
   120→  const slugger = new GithubSlugger();
   121→  let match;
   122→
   123→  while ((match = regex.exec(content)) !== null) {
   124→    const level = match[1].length;
   125→    const text = match[2].trim();
   126→    const id = slugger.slug(text);
   127→    
   128→    headings.push({ id, text, level });
   129→  }
   130→  return headings;
   131→}
   132→
   133→/**
   134→ * Read explicitly configured authors from a series index file's frontmatter.
   135→ * Returns null if no authors are configured (as opposed to the default fallback).
   136→ */
   137→export function getSeriesAuthors(seriesSlug: string): string[] | null {
   138→  if (!fs.existsSync(seriesDirectory)) return null;
   139→  const indexPathMdx = path.join(seriesDirectory, seriesSlug, 'index.mdx');
   140→  const indexPathMd = path.join(seriesDirectory, seriesSlug, 'index.md');
   141→
   142→  let fullPath = '';
   143→  if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   144→  else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   145→  else return null;
   146→
   147→  const { data } = matter(fs.readFileSync(fullPath, 'utf8'));
   148→  if (data.authors && Array.isArray(data.authors) && data.authors.length > 0) {
   149→    return data.authors;
   150→  }
   151→  if (data.author && typeof data.author === 'string') {
   152→    return [data.author];
   153→  }
   154→  return null;
   155→}
   156→
   157→function parseMarkdownFile(fullPath: string, slug: string, dateFromFileName?: string, seriesName?: string): PostData {
   158→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   159→  const { data: rawData, content } = matter(fileContents);
   160→
   161→  const parsed = PostSchema.safeParse(rawData);
   162→  if (!parsed.success) {
   163→    console.error(`Invalid frontmatter in ${fullPath}:`, parsed.error.format());
   164→    throw new Error(`Invalid frontmatter in ${fullPath}`);
   165→  }
   166→  const data = parsed.data;
   167→
   168→  const contentWithoutH1 = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   169→
   170→  let authors: string[] = [];
   171→  if (data.authors && Array.isArray(data.authors)) {
   172→    authors = data.authors;
   173→  } else if (data.author) {
   174→    authors = [data.author];
   175→  } else {
   176→    // Inherit from series if this post belongs to one
   177→    const seriesSlug = data.series || seriesName;
   178→    if (seriesSlug) {
   179→      const seriesAuthors = getSeriesAuthors(seriesSlug);
   180→      if (seriesAuthors) {
   181→        authors = seriesAuthors;
   182→      }
   183→    }
   184→    if (authors.length === 0) {
   185→      const defaultAuthors = siteConfig.posts?.authors?.default;
   186→      if (defaultAuthors && defaultAuthors.length > 0) {
   187→        authors = defaultAuthors;
   188→      }
   189→    }
   190→  }
   191→
   192→  const excerpt = data.excerpt || generateExcerpt(contentWithoutH1);
   193→  const readingTime = calculateReadingTime(contentWithoutH1);
   194→  
   195→  let date = data.date;
   196→  if (!date && dateFromFileName) date = dateFromFileName;
   197→  if (!date) date = new Date().toISOString().split('T')[0]; // Fallback
   198→
   199→  const headings = getHeadings(content);
   200→
   201→  let coverImage = data.coverImage;
   202→  if (coverImage && !coverImage.startsWith('http') && !coverImage.startsWith('/') && !coverImage.startsWith('text:')) {
   203→    const cleanPath = coverImage.replace(/^\.\//, '');
   204→    coverImage = `/posts/${slug}/${cleanPath}`;
   205→  }
   206→
   207→  return {
   208→    slug,
   209→    title: data.title,
   210→    subtitle: data.subtitle,
   211→    date,
   212→    excerpt,
   213→    category: data.category,
   214→    tags: data.tags,
   215→    authors,
   216→    layout: data.layout,
   217→    series: data.series || seriesName,
   218→    coverImage,
   219→    sort: data.sort,
   220→    posts: data.posts,
   221→    featured: data.featured,
   222→    pinned: data.pinned,
   223→    draft: data.draft,
   224→    latex: data.latex,
   225→    toc: data.toc,
   226→    externalLinks: data.externalLinks,
   227→    readingTime,
   228→    content: contentWithoutH1,
   229→    headings,
   230→  };
   231→}
   232→
   233→export function getAllPosts(): PostData[] {
   234→  const allPostsData: PostData[] = [];
   235→
   236→  // Helper to process a directory
   237→  const processDirectory = (dir: string, isSeriesDir: boolean = false) => {
   238→    if (!fs.existsSync(dir)) return;
   239→    
   240→    const items = fs.readdirSync(dir, { withFileTypes: true });
   241→
   242→    items.forEach((item) => {
   243→      let fullPath = '';
   244→      let slug = '';
   245→      let dateFromFileName = undefined;
   246→
   247→      const dateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
   248→      const rawName = item.name.replace(/\.mdx?$/, '');
   249→      const match = rawName.match(dateRegex);
   250→      
   251→      if (match) {
   252→        dateFromFileName = match[1];
   253→        if (siteConfig.posts?.includeDateInUrl) {
   254→          slug = rawName;
   255→        } else {
   256→          slug = match[2];
   257→        }
   258→      } else {
   259→        slug = rawName;
   260→      }
   261→
   262→      // Handle Series Directory logic
   263→      if (isSeriesDir) {
   264→        if (item.isDirectory()) {
   265→           const seriesSlug = item.name; // Folder name is series slug
   266→           const seriesPath = path.join(dir, item.name);
   267→           const seriesItems = fs.readdirSync(seriesPath, { withFileTypes: true });
   268→           
   269→           seriesItems.forEach(sItem => {
   270→             // Skip series metadata file itself
   271→             if (sItem.name === 'index.md' || sItem.name === 'index.mdx') return;
   272→
   273→             // 1. File-based posts: series/slug/post.mdx
   274→             if (sItem.isFile() && (sItem.name.endsWith('.md') || sItem.name.endsWith('.mdx'))) {
   275→               const sRawName = sItem.name.replace(/\.mdx?$/, '');
   276→               const sMatch = sRawName.match(dateRegex);
   277→               let sSlug = sRawName;
   278→               let sDate = undefined;
   279→               if (sMatch) {
   280→                 sDate = sMatch[1];
   281→                 sSlug = siteConfig.posts?.includeDateInUrl ? sRawName : sMatch[2];
   282→               }
   283→               
   284→               allPostsData.push(parseMarkdownFile(
   285→                 path.join(seriesPath, sItem.name), 
   286→                 sSlug, 
   287→                 sDate, 
   288→                 seriesSlug 
   289→               ));
   290→             } 
   291→             // 2. Folder-based posts: series/slug/post-folder/index.mdx
   292→             else if (sItem.isDirectory()) {
   293→                 const postFolder = path.join(seriesPath, sItem.name);
   294→                 const postIndexMdx = path.join(postFolder, 'index.mdx');
   295→                 const postIndexMd = path.join(postFolder, 'index.md');
   296→                 let postFullPath = '';
   297→                 
   298→                 if (fs.existsSync(postIndexMdx)) postFullPath = postIndexMdx;
   299→                 else if (fs.existsSync(postIndexMd)) postFullPath = postIndexMd;
   300→                 
   301→                 if (postFullPath) {
   302→                     // Handle date prefix in folder name
   303→                     const sMatch = sItem.name.match(dateRegex);
   304→                     let sSlug = sItem.name;
   305→                     let sDate = undefined;
   306→                     
   307→                     if (sMatch) {
   308→                       sDate = sMatch[1];
   309→                       sSlug = siteConfig.posts?.includeDateInUrl ? sItem.name : sMatch[2];
   310→                     }
   311→
   312→                     allPostsData.push(parseMarkdownFile(
   313→                       postFullPath, 
   314→                       sSlug, 
   315→                       sDate, 
   316→                       seriesSlug 
   317→                     ));
   318→                 }
   319→             }
   320→           });
   321→           return; // Processed this series folder
   322→        }
   323→      }
   324→
   325→      // Standard Posts logic (outside series)
   326→      if (item.isFile()) {
   327→        if (!item.name.endsWith('.mdx') && !item.name.endsWith('.md')) return;
   328→        fullPath = path.join(dir, item.name);
   329→        allPostsData.push(parseMarkdownFile(fullPath, slug, dateFromFileName));
   330→      } else if (item.isDirectory()) {
   331→        const indexPathMdx = path.join(dir, item.name, 'index.mdx');
   332→        const indexPathMd = path.join(dir, item.name, 'index.md');
   333→        if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   334→        else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   335→        else return;
   336→        
   337→        allPostsData.push(parseMarkdownFile(fullPath, slug, dateFromFileName));
   338→      }
   339→    });
   340→  };
   341→
   342→  processDirectory(contentDirectory);
   343→  processDirectory(seriesDirectory, true);
   344→
   345→  return allPostsData
   346→    .filter(post => {
   347→      if (post.category === 'Page') return false;
   348→      
   349→      if (process.env.NODE_ENV === 'production' && post.draft) {
   350→        return false;
   351→      }
   352→
   353→      if (!siteConfig.posts?.showFuturePosts) {
   354→        const postDate = new Date(post.date);
   355→        const now = new Date();
   356→        if (postDate > now) return false;
   357→      }
   358→      return true;
   359→    })
   360→    .sort((a, b) => (a.date < b.date ? 1 : -1));
   361→}
