   363→/**
   364→ * Returns posts for the main listing pages, honouring posts.excludeFromListing.
   365→ * Use this instead of getAllPosts() on any listing/pagination page.
   366→ * Individual post routes and series pages still use getAllPosts() directly.
   367→ */
   368→export function getListingPosts(): PostData[] {
   369→  const excluded = new Set(siteConfig.posts?.excludeFromListing ?? []);
   370→  if (excluded.size === 0) return getAllPosts();
   371→  return getAllPosts().filter(p => !p.series || !excluded.has(p.series));
