   373→
   374→function findPostFile(name: string, targetSlug: string): PostData | null {
   375→  // Check standard posts
   376→  let fullPath = path.join(contentDirectory, `${name}.mdx`);
   377→  if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   378→  
   379→  fullPath = path.join(contentDirectory, `${name}.md`);
   380→  if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   381→
   382→  if (fs.existsSync(path.join(contentDirectory, name))) {
   383→    fullPath = path.join(contentDirectory, name, 'index.mdx');
   384→    if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   385→    
   386→    fullPath = path.join(contentDirectory, name, 'index.md');
   387→    if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug);
   388→  }
   389→
   390→  // Check series posts
   391→  if (fs.existsSync(seriesDirectory)) {
   392→    const seriesFolders = fs.readdirSync(seriesDirectory);
   393→    for (const folder of seriesFolders) {
   394→      const folderPath = path.join(seriesDirectory, folder);
   395→      if (!fs.statSync(folderPath).isDirectory()) continue;
   396→
   397→      // Check file-based
   398→      fullPath = path.join(folderPath, `${name}.mdx`);
   399→      if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   400→
   401→      fullPath = path.join(folderPath, `${name}.md`);
   402→      if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   403→
   404→      // Check folder-based
   405→      const postFolderPath = path.join(folderPath, name);
   406→      if (fs.existsSync(postFolderPath) && fs.statSync(postFolderPath).isDirectory()) {
   407→         fullPath = path.join(postFolderPath, 'index.mdx');
   408→         if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   409→         
   410→         fullPath = path.join(postFolderPath, 'index.md');
   411→         if (fs.existsSync(fullPath)) return parseMarkdownFile(fullPath, targetSlug, undefined, folder);
   412→      }
   413→    }
   414→  }
   415→
   416→  return null;
   417→}
   418→
   419→export function getPostBySlug(slug: string): PostData | null {
   420→  let post: PostData | null = null;
   421→
   422→  if (siteConfig.posts?.includeDateInUrl) {
   423→    post = findPostFile(slug, slug);
   424→  } else {
   425→    post = findPostFile(slug, slug);
   426→    if (!post) {
   427→        // Search in content/posts
   428→        const items = fs.existsSync(contentDirectory) ? fs.readdirSync(contentDirectory) : [];
   429→        for (const item of items) {
   430→          const rawName = item.replace(/\.mdx?$/, '');
   431→          const dateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
   432→          const match = rawName.match(dateRegex);
   433→          
   434→          if (match && match[2] === slug) {
   435→            post = findPostFile(rawName, slug);
   436→            break;
   437→          }
   438→        }
   439→
   440→        // If not found, search in series folders
   441→        if (!post && fs.existsSync(seriesDirectory)) {
   442→           const seriesFolders = fs.readdirSync(seriesDirectory);
   443→           for (const folder of seriesFolders) {
   444→             const folderPath = path.join(seriesDirectory, folder);
   445→             if (!fs.statSync(folderPath).isDirectory()) continue;
   446→             
   447→             const sItems = fs.readdirSync(folderPath);
   448→             for (const sItem of sItems) {
   449→                const sRawName = sItem.replace(/\.mdx?$/, '');
   450→                // Also check folders
   451→                const sDateRegex = /^(\d{4}-\d{2}-\d{2})-(.*)$/;
   452→                const sMatch = sRawName.match(sDateRegex);
   453→                
   454→                if (sMatch && sMatch[2] === slug) {
   455→                  post = findPostFile(sRawName, slug);
   456→                  break;
   457→                }
   458→             }
   459→             if (post) break;
   460→           }
   461→        }
   462→    }
   463→  }
   464→
   465→  if (!post) return null;
   466→
   467→  if (process.env.NODE_ENV === 'production' && post.draft) {
   468→    return null;
   469→  }
   470→
   471→  if (!siteConfig.posts?.showFuturePosts) {
   472→      const postDate = new Date(post.date);
   473→      const now = new Date();
   474→      if (postDate > now) return null;
   475→  }
   476→  return post;
   477→}
   478→
   479→/**
   480→ * Load the content and frontmatter of a locale variant file, e.g. about.zh.mdx.
   481→ * Returns null when the file does not exist or cannot be parsed.
   482→ */
   483→function loadLocaleContent(slug: string, locale: string): { content: string; title?: string; excerpt?: string; headings?: Heading[] } | null {
   484→  for (const ext of ['.mdx', '.md']) {
   485→    const filePath = path.join(pagesDirectory, `${slug}.${locale}${ext}`);
   486→    if (fs.existsSync(filePath)) {
   487→      try {
   488→        const { data, content } = matter(fs.readFileSync(filePath, 'utf8'));
   489→        const body = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   490→        return {
   491→          content: body,
   492→          title: typeof data.title === 'string' ? data.title : undefined,
   493→          excerpt: typeof data.excerpt === 'string' ? data.excerpt : undefined,
   494→          headings: getHeadings(body),
   495→        };
   496→      } catch {
   497→        return null;
   498→      }
   499→    }
   500→  }

