   608→export function getAuthorSlug(author: string): string {
   609→  const slugger = new GithubSlugger();
   610→  // Normalize all Unicode dash punctuation to ASCII hyphen, then trim edges.
   611→  // This avoids runtime-specific outputs like wrapped dash variants.
   612→  return slugger
   613→    .slug(author.trim())
