   618→export function getAllAuthors(): Record<string, number> {
   619→  const allPosts = getAllPosts();
   620→  const authors: Record<string, number> = {};
   621→
   622→  allPosts.forEach((post) => {
   623→    post.authors.forEach((author) => {
   624→      if (authors[author]) {
   625→        authors[author] += 1;
   626→      } else {
   627→        authors[author] = 1;
   628→      }
   629→    });
   630→  });
   631→
