   635→export function resolveAuthorParam(authorParam: string): string | null {
   636→  const allAuthors = Object.keys(getAllAuthors());
   637→  const normalizedParam = authorParam.trim().toLowerCase();
   638→
   639→  // Backward compatibility for name-based URLs (/authors/Amytis%20Team).
   640→  const exactMatch = allAuthors.find((author) => author.toLowerCase() === normalizedParam);
   641→  if (exactMatch) return exactMatch;
   642→
   643→  // Preferred slug-based URLs (/authors/amytis-team).
   644→  const slugMatch = allAuthors.find((author) => getAuthorSlug(author) === normalizedParam);
   645→  return slugMatch || null;
   646→}
