   675→export function getSeriesPosts(seriesName: string): PostData[] {
   676→  const seriesSlug = seriesName;
   677→  const seriesData = getSeriesData(seriesSlug);
   678→  
   679→  let posts: PostData[] = [];
   680→  
   681→  if (seriesData?.posts && seriesData.posts.length > 0) {
   682→      // Manual Selection: fetch by slug
   683→      posts = seriesData.posts
   684→        .map(slug => getPostBySlug(slug))
   685→        .filter((p): p is PostData => p !== null);
   686→  } else {
   687→      // Automatic: posts with series field matching this series
   688→      const allPosts = getAllPosts();
   689→      posts = allPosts.filter(p => p.series === seriesName);
   690→      
   691→      // Default Sort: date-desc (Newest first)
   692→      const sortOrder = seriesData?.sort || 'date-desc';
   693→      if (sortOrder === 'date-asc') {
   694→          posts.sort((a, b) => (a.date > b.date ? 1 : -1));
   695→      } else {
   696→          posts.sort((a, b) => (a.date < b.date ? 1 : -1));
   697→      }
   698→  }
   699→  
   700→  return posts;
