   703→export function getAllSeries(): Record<string, PostData[]> {
   704→  const allPosts = getAllPosts();
   705→  const series: Record<string, PostData[]> = {};
   706→  const seriesSet = new Set<string>();
   707→
   708→  // 1. Collect series from posts
   709→  allPosts.forEach((post) => {
   710→    if (post.series) {
   711→      seriesSet.add(post.series);
   712→    }
   713→  });
   714→
   715→  // 2. Collect series from folders (in case no posts are yet tagged but folder exists)
   716→  if (fs.existsSync(seriesDirectory)) {
   717→    const seriesFolders = fs.readdirSync(seriesDirectory, { withFileTypes: true });
   718→    seriesFolders.forEach(folder => {
   719→      if (folder.isDirectory()) {
   720→        seriesSet.add(folder.name);
   721→      }
   722→    });
   723→  }
   724→
   725→  // 3. Fetch posts for each series, filtering out draft series in production
   726→  seriesSet.forEach(slug => {
   727→    const seriesData = getSeriesData(slug);
   728→    if (process.env.NODE_ENV === 'production' && seriesData?.draft) {
   729→      return; // Skip draft series in production
   730→    }
   731→    series[slug] = getSeriesPosts(slug);
   732→  });
   733→
   734→  return series;
   735→}
