   752→export function getFeaturedSeries(): Record<string, PostData[]> {
   753→  const allSeries = getAllSeries();
   754→  const featuredSeries: Record<string, PostData[]> = {};
   755→  
   756→  Object.keys(allSeries).forEach(slug => {
   757→    const seriesData = getSeriesData(slug);
   758→    if (seriesData?.featured) {
   759→      featuredSeries[slug] = allSeries[slug];
   760→    }
   761→  });
   762→  
   763→  return featuredSeries;
   764→}
