   766→export function getSeriesData(slug: string): PostData | null {
   767→  if (!fs.existsSync(seriesDirectory)) return null;
   768→  const indexPathMdx = path.join(seriesDirectory, slug, 'index.mdx');
   769→  const indexPathMd = path.join(seriesDirectory, slug, 'index.md');
   770→  
   771→  let fullPath = '';
   772→  if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   773→  else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   774→  else return null;
   775→
   776→  return parseMarkdownFile(fullPath, slug, undefined, slug);
