   157→function parseMarkdownFile(fullPath: string, slug: string, dateFromFileName?: string, seriesName?: string): PostData {
   158→  const fileContents = fs.readFileSync(fullPath, 'utf8');
   159→  const { data: rawData, content } = matter(fileContents);
   160→
   161→  const parsed = PostSchema.safeParse(rawData);
   162→  if (!parsed.success) {
   163→    console.error(`Invalid frontmatter in ${fullPath}:`, parsed.error.format());
   164→    throw new Error(`Invalid frontmatter in ${fullPath}`);
   165→  }
   166→  const data = parsed.data;
   167→
   168→  const contentWithoutH1 = content.replace(/^\s*#\s+[^\n]+/, '').trim();
   169→
   170→  let authors: string[] = [];
   171→  if (data.authors && Array.isArray(data.authors)) {
   172→    authors = data.authors;
   173→  } else if (data.author) {
   174→    authors = [data.author];
   175→  } else {
   176→    // Inherit from series if this post belongs to one
   177→    const seriesSlug = data.series || seriesName;
   178→    if (seriesSlug) {
   179→      const seriesAuthors = getSeriesAuthors(seriesSlug);
   180→      if (seriesAuthors) {
   181→        authors = seriesAuthors;
   182→      }
   183→    }
   184→    if (authors.length === 0) {
   185→      const defaultAuthors = siteConfig.posts?.authors?.default;
   186→      if (defaultAuthors && defaultAuthors.length > 0) {
   187→        authors = defaultAuthors;
   188→      }
   189→    }
   190→  }
   191→
   192→  const excerpt = data.excerpt || generateExcerpt(contentWithoutH1);
   193→  const readingTime = calculateReadingTime(contentWithoutH1);
   194→  
   195→  let date = data.date;
   196→  if (!date && dateFromFileName) date = dateFromFileName;
   197→  if (!date) date = new Date().toISOString().split('T')[0]; // Fallback
   198→
   199→  const headings = getHeadings(content);
   200→
   201→  let coverImage = data.coverImage;
   202→  if (coverImage && !coverImage.startsWith('http') && !coverImage.startsWith('/') && !coverImage.startsWith('text:')) {
   203→    const cleanPath = coverImage.replace(/^\.\//, '');
   204→    coverImage = `/posts/${slug}/${cleanPath}`;
   205→  }
   206→
   207→  return {
   208→    slug,
   209→    title: data.title,
   210→    subtitle: data.subtitle,
   211→    date,
   212→    excerpt,
   213→    category: data.category,
   214→    tags: data.tags,
   215→    authors,
   216→    layout: data.layout,
   217→    series: data.series || seriesName,
   218→    coverImage,
   219→    sort: data.sort,
   220→    posts: data.posts,
   221→    featured: data.featured,
   222→    pinned: data.pinned,
   223→    draft: data.draft,
