     3→import { useRef, useState, useEffect, ReactNode, useCallback } from 'react';
     4→
     5→interface HorizontalScrollProps {
     6→  children: ReactNode;
     7→  itemCount: number;
     8→  scrollThreshold: number;
     9→  className?: string;
    10→}
    11→
    12→export default function HorizontalScroll({
    13→  children,
    14→  itemCount,
    15→  scrollThreshold,
    16→  className = ''
    17→}: HorizontalScrollProps) {
    18→  const scrollRef = useRef<HTMLDivElement>(null);
    19→  const containerRef = useRef<HTMLDivElement>(null);
    20→  const [canScrollLeft, setCanScrollLeft] = useState(false);
    21→  const [canScrollRight, setCanScrollRight] = useState(false);
    22→
    23→  const shouldShowArrows = itemCount > scrollThreshold;
    24→
    25→  const updateScrollState = useCallback(() => {
    26→    if (!scrollRef.current) return;
    27→    const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
    28→    setCanScrollLeft(scrollLeft > 0);
    29→    setCanScrollRight(scrollLeft < scrollWidth - clientWidth - 1);
    30→  }, []);
    31→
    32→  useEffect(() => {
    33→    updateScrollState();
    34→    const container = scrollRef.current;
    35→    if (container) {
    36→      container.addEventListener('scroll', updateScrollState);
    37→      window.addEventListener('resize', updateScrollState);
    38→    }
    39→    return () => {
    40→      if (container) {
    41→        container.removeEventListener('scroll', updateScrollState);
    42→      }
    43→      window.removeEventListener('resize', updateScrollState);
    44→    };
    45→  }, [updateScrollState]);
    46→
    47→  const scroll = useCallback((direction: 'left' | 'right') => {
    48→    if (!scrollRef.current) return;
    49→    const container = scrollRef.current;
    50→    const scrollAmount = container.clientWidth * 0.8;
    51→    container.scrollBy({
    52→      left: direction === 'left' ? -scrollAmount : scrollAmount,
    53→      behavior: 'smooth'
    54→    });
    55→  }, []);
    56→
    57→  // Handle keyboard navigation
    58→  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    59→    if (e.key === 'ArrowLeft' && canScrollLeft) {
    60→      e.preventDefault();
    61→      scroll('left');
    62→    } else if (e.key === 'ArrowRight' && canScrollRight) {
    63→      e.preventDefault();
    64→      scroll('right');
    65→    }
    66→  }, [canScrollLeft, canScrollRight, scroll]);
    67→
    68→  if (!shouldShowArrows) {
    69→    return <div className={className}>{children}</div>;
    70→  }
    71→
    72→  return (
    73→    <div
    74→      ref={containerRef}
    75→      className="relative group/scroll overflow-visible"
    76→      onKeyDown={handleKeyDown}
    77→      tabIndex={0}
    78→      role="region"
    79→      aria-label="Scrollable content"
    80→    >
    81→      {/* Left Arrow - positioned outside content in margin area */}
    82→      <button
    83→        onClick={() => scroll('left')}
    84→        className={`absolute -left-4 lg:-left-14 top-1/2 -translate-y-1/2 z-20 p-2 lg:p-3 bg-background border border-muted/20 rounded-full shadow-lg transition-all duration-200 hidden md:flex items-center justify-center ${
    85→          canScrollLeft
    86→            ? 'text-muted hover:text-accent hover:border-accent/40 hover:shadow-accent/10 focus:outline-none focus:ring-2 focus:ring-accent/50'
    87→            : 'text-muted/30 cursor-not-allowed opacity-50'
    88→        }`}
    89→        disabled={!canScrollLeft}
    90→        aria-label="Scroll left"
    91→        tabIndex={canScrollLeft ? 0 : -1}
    92→      >
    93→        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={canScrollLeft ? 'group-hover/scroll:-translate-x-0.5 transition-transform' : ''}>
    94→          <polyline points="15 18 9 12 15 6"></polyline>
    95→        </svg>
    96→      </button>
    97→
    98→      {/* Scrollable Container */}
    99→      <div
   100→        ref={scrollRef}
   101→        className={`overflow-x-auto scrollbar-hide scroll-smooth snap-x snap-mandatory ${className}`}
   102→        style={{ scrollSnapType: 'x mandatory' }}
   103→      >
   104→        {children}
   105→      </div>
   106→
   107→      {/* Right Arrow - positioned outside content in margin area */}
   108→      <button
   109→        onClick={() => scroll('right')}
   110→        className={`absolute -right-4 lg:-right-14 top-1/2 -translate-y-1/2 z-20 p-2 lg:p-3 bg-background border border-muted/20 rounded-full shadow-lg transition-all duration-200 hidden md:flex items-center justify-center ${
   111→          canScrollRight
