   689→export function getSeriesPosts(seriesName: string): PostData[] {
   690→  const seriesSlug = seriesName;
   691→  const seriesData = getSeriesData(seriesSlug);
   692→  
   693→  let posts: PostData[] = [];
   694→  
   695→  if (seriesData?.posts && seriesData.posts.length > 0) {
   696→      // Manual Selection: fetch by slug
   697→      posts = seriesData.posts
   698→        .map(slug => getPostBySlug(slug))
   699→        .filter((p): p is PostData => p !== null);
   700→  } else {
   701→      // Automatic: posts with series field matching this series
   702→      const allPosts = getAllPosts();
   703→      posts = allPosts.filter(p => p.series === seriesName);
   704→      
   705→      // Default Sort: date-desc (Newest first)
   706→      const sortOrder = seriesData?.sort || 'date-desc';
   707→      if (sortOrder === 'date-asc') {
   708→          posts.sort((a, b) => (a.date > b.date ? 1 : -1));
   709→      } else {
   710→          posts.sort((a, b) => (a.date < b.date ? 1 : -1));
   711→      }
   712→  }
   713→  
   714→  return posts;
   715→}
   716→
   717→export function getAllSeries(): Record<string, PostData[]> {
   718→  const allPosts = getAllPosts();
   719→  const series: Record<string, PostData[]> = {};
   720→  const seriesSet = new Set<string>();
   721→
   722→  // 1. Collect series from posts
   723→  allPosts.forEach((post) => {
   724→    if (post.series) {
   725→      seriesSet.add(post.series);
   726→    }
   727→  });
   728→
   729→  // 2. Collect series from folders (in case no posts are yet tagged but folder exists)
   730→  if (fs.existsSync(seriesDirectory)) {
   731→    const seriesFolders = fs.readdirSync(seriesDirectory, { withFileTypes: true });
   732→    seriesFolders.forEach(folder => {
   733→      if (folder.isDirectory()) {
   734→        seriesSet.add(folder.name);
   735→      }
   736→    });
   737→  }
   738→
   739→  // 3. Fetch posts for each series, filtering out draft series in production
   740→  seriesSet.forEach(slug => {
   741→    const seriesData = getSeriesData(slug);
   742→    if (process.env.NODE_ENV === 'production' && seriesData?.draft) {
   743→      return; // Skip draft series in production
   744→    }
   745→    series[slug] = getSeriesPosts(slug);
   746→  });
   747→
   748→  return series;
   749→}
   750→
   751→export function getFeaturedPosts(): PostData[] {
   752→  const allPosts = getAllPosts();
   753→  return allPosts.filter(post => post.featured);
   754→}
   755→
   756→export function getAdjacentPosts(slug: string): { prev: PostData | null; next: PostData | null } {
   757→  const allPosts = getAllPosts(); // sorted desc by date (newest first)
   758→  const index = allPosts.findIndex(p => p.slug === slug);
   759→  if (index === -1) return { prev: null, next: null };
   760→  return {
   761→    prev: index < allPosts.length - 1 ? allPosts[index + 1] : null, // older post
   762→    next: index > 0 ? allPosts[index - 1] : null,                   // newer post
   763→  };
   764→}
   765→
   766→export function getFeaturedSeries(): Record<string, PostData[]> {
   767→  const allSeries = getAllSeries();
   768→  const featuredSeries: Record<string, PostData[]> = {};
   769→  
   770→  Object.keys(allSeries).forEach(slug => {
   771→    const seriesData = getSeriesData(slug);
   772→    if (seriesData?.featured) {
   773→      featuredSeries[slug] = allSeries[slug];
   774→    }
   775→  });
   776→  
   777→  return featuredSeries;
   778→}
   779→
   780→export function getSeriesData(slug: string): PostData | null {
   781→  if (!fs.existsSync(seriesDirectory)) return null;
   782→  const indexPathMdx = path.join(seriesDirectory, slug, 'index.mdx');
   783→  const indexPathMd = path.join(seriesDirectory, slug, 'index.md');
   784→  
   785→  let fullPath = '';
   786→  if (fs.existsSync(indexPathMdx)) fullPath = indexPathMdx;
   787→  else if (fs.existsSync(indexPathMd)) fullPath = indexPathMd;
   788→  else return null;
   789→
   790→  return parseMarkdownFile(fullPath, slug, undefined, slug);
   791→}
